function createMap(
  language: string,
  row: string,
): Record<HeroSliderSource, string> {
  const translations = [
    ...row.split("|"),
    ...EXTRA_ROWS[language as LocalizedLanguage].split("|"),
  ];
  if (translations.length !== HERO_SLIDER_SOURCE_STRINGS.length) {
    throw new Error(
      `${language} hero slider translations must have ${HERO_SLIDER_SOURCE_STRINGS.length} entries, received ${translations.length}.`,
    );
  }

  return Object.fromEntries(
    HERO_SLIDER_SOURCE_STRINGS.map((source, index) => [
      source,
      translations[index] ?? source,
    ]),
  ) as Record<HeroSliderSource, string>;
}

export const HERO_SLIDER_SOURCE_TRANSLATIONS = Object.fromEntries(
  Object.entries(ROWS).map(([language, row]) => [
    language,
    createMap(language, row),
  ]),
) as Record<LocalizedLanguage, Record<HeroSliderSource, string>>;
